"use client";

import { Area, AreaChart, CartesianGrid, XAxis, YAxis } from "recharts";
import { ArrowUpRight, DollarSign } from "lucide-react";
import {
  Card,
  CardContent,

  CardHeader,

} from "@/components/ui/card";
import {
  type ChartConfig,
  ChartContainer,
  ChartTooltip,
} from "@/components/ui/chart";
import { Badge } from "@/components/ui/badge";

const chartData = [
  { date: "Jan 01", net: 45000, gross: 52000 },
  { date: "Jan 03", net: 52000, gross: 60000 },
  { date: "Jan 05", net: 48000, gross: 55000 },
  { date: "Jan 07", net: 61000, gross: 70000 },
  { date: "Jan 09", net: 55000, gross: 65000 },
  { date: "Jan 11", net: 67000, gross: 78000 },
  { date: "Jan 13", net: 72000, gross: 85000 },
  { date: "Jan 15", net: 68000, gross: 80000 },
  { date: "Jan 17", net: 85000, gross: 98000 },
  { date: "Jan 19", net: 79000, gross: 92000 },
  { date: "Today", net: 92000, gross: 105000 },
];

const chartConfig = {
  net: {
    label: "Net Revenue",
    color: "hsl(var(--muted-foreground))",
  },
  gross: {
    label: "Gross Revenue",
    color: "hsl(var(--primary))",
  },
} satisfies ChartConfig;

export function RevenueChart() {
  return (
    <Card className="w-full rounded-none shadow-sm p-0.5 bg-zinc-100 dark:bg-zinc-800 gap-0 border-none group/card">
      <CardHeader className="w-full px-2 mt-1">
        <div className="flex items-center gap-2 text-muted-foreground">
          <DollarSign className="w-4 h-4 group-hover/card:text-primary transition-colors duration-300" />
          <span className="text-lg font-medium text-foreground">
            Net revenue
          </span>
        </div>
      </CardHeader>
      <CardContent className="px-2 py-4 sm:px-4  bg-white dark:bg-zinc-900">
        <div className="flex items-baseline gap-2">
          <h2 className="text-2xl font-medium tracking-tight tabular-nums">
            ₹18,46,720
          </h2>
          <Badge className="bg-green-500/20 text-green-600 hover:bg-green-500/30 transition-colors duration-200 border-none px-1.5 py-0.5 flex gap-0.5 items-center font-medium cursor-pointer">
            <ArrowUpRight className="size-5 stroke-2" /> 5.7%
          </Badge>
        </div>
        <ChartContainer
          config={chartConfig}
          className="aspect-[auto] h-[200px] "
        >
          <AreaChart
            accessibilityLayer
            data={chartData}
            margin={{ left: 10, right: 10, top: 10, bottom: 0 }}
          >
            <defs>
              <linearGradient id="fillNet" x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor="var(--net)" stopOpacity={0.45} />
                <stop
                  offset="100%"
                  stopColor="var(--color-net)"
                  stopOpacity={0.01}
                />
              </linearGradient>
            </defs>
            <CartesianGrid
              vertical={false}
              strokeDasharray="3 3"
              className="stroke-muted/50"
            />
            <XAxis
              dataKey="date"
              tickLine={false}
              axisLine={{
                stroke: "var(--foreground)",
                strokeWidth: 1,
                opacity: 0.2,
              }}
              tickMargin={12}
              interval={0}
              ticks={[chartData[0].date, chartData[chartData.length - 1].date]}
              padding={{ left: 10, right: 10 }}
              className="text-xs text-foreground uppercase"
            />
            <YAxis hide domain={["dataMin - 10000", "dataMax + 10000"]} />
            <ChartTooltip
              cursor={{
                stroke: "hsl(var(--foreground))",
                strokeWidth: 1,
              }}
              content={({ active, payload, label }) => {
                if (active && payload && payload.length) {
                  return (
                    <div className="w-auto bg-zinc-100 border border-slate-200 dark:bg-zinc-800 dark:border-zinc-700 shadow-xl p-2 rounded-sm">
                      <p className="text-sm font-medium text-foreground mb-2 uppercase tracking-tight">
                        {label}
                      </p>

                      <div className="flex flex-col gap-1">
                        <div className="flex justify-between items-center text-xs gap-12">
                          <span className="text-muted-foreground font-medium">
                            Gross Revenue:
                          </span>
                          <span className="font-medium tabular-nums">
                            ₹{payload[0].payload.gross.toLocaleString("en-IN")}
                          </span>
                        </div>
                        <div className="flex justify-between items-center text-xs gap-16">
                          <span className="text-muted-foreground font-medium">
                            Net Revenue:
                          </span>
                          <span className="font-medium tabular-nums text-foreground">
                            ₹{payload[0].payload.net.toLocaleString("en-IN")}
                          </span>
                        </div>
                      </div>
                    </div>
                  );
                }
                return null;
              }}
            />
            <Area
              dataKey="net"
              type="monotone"
              fill="url(#fillNet)"
              fillOpacity={1}
              stroke="var(--color-net)"
              strokeWidth={2}
              stackId="a"
            />
          </AreaChart>
        </ChartContainer>
      </CardContent>
    </Card>
  );
}

import { Moon, Sun } from "lucide-react";
import { useTheme } from "next-themes";

import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

export function ModeToggle() {
  const { setTheme } = useTheme();

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="outline" size="icon" className="relative transition-colors duration-300 shadow-sm">
          <Sun className="h-[1.2rem] w-[1.2rem] scale-100 rotate-0 transition-all dark:scale-0 dark:-rotate-90 group-hover:text-primary" />
          <Moon className="absolute h-[1.2rem] w-[1.2rem] scale-0 rotate-90 transition-all dark:scale-100 dark:rotate-0 group-hover:text-primary" />
          <span className="sr-only">Toggle theme</span>
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        <DropdownMenuItem onClick={() => setTheme("light")}>
          Light
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => setTheme("dark")}>
          Dark
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => setTheme("system")}>
          System
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

"use client";
import { AppSidebar } from "./components/app-sidebar";
import { SidebarProvider } from "@/components/ui/sidebar";

export const DashboardLayout = ({
  children,
}: {
  children: React.ReactNode;
}) => {
  return (
    <div className="bg-white dark:bg-white/5  h-svh w-screen overflow-hidden font-sans">
      <SidebarProvider
        className="h-full min-h-0! overflow-hidden gap-2 "
        style={
          {
            "--sidebar-width": "calc(var(--spacing) * 60)",
            "--header-height": "calc(var(--spacing) * 12)",
          } as React.CSSProperties
        }
      >
        <AppSidebar className="group" />

        {children}
      </SidebarProvider>
    </div>
  );
};

"use client";
import { FailedPayments } from "./components/failed-payment";
import { DashboardHeader } from "./components/header";
import { PaymentsSummary } from "./components/payment-summary";
import { RevenueChart } from "./components/revenue-charts";
import { TransactionsTable } from "./components/transaction-table";
import { SidebarTrigger, useSidebar } from "@/components/ui/sidebar";

export default function DashboardView() {
  const { isMobile } = useSidebar();

  return (
    <div className="flex flex-col min-h-screen w-full px-4 md:px-12 pt-16 pb-4 2xl:px-40 font-sans  gap-8 overflow-y-scroll overflow-x-hidden">
      {isMobile && <SidebarTrigger className="absolute inset-0" />}
      <DashboardHeader />
      <RevenueChart />
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <PaymentsSummary />
        <FailedPayments />
      </div>
      <TransactionsTable />
    </div>
  );
}

import { DashboardLayout } from "./dashboardLayout";
import DashboardView from "./dashboardView";

export default function PaymentOperationsDemo() {
  return (
    <DashboardLayout>
      <DashboardView />
    </DashboardLayout>
  );
}
